mapper.select:
SELECT  
  FROM  TB_BATCH_SCHDUL A
 WHERE  A.BATCH_SCHDUL_ID = #{batchSchdulId}

mapper.insert:
INSERT  INTO TB_BATCH_SCHDUL
      ( BATCH_SCHDUL_ID
      , BATCH_OPERT_ID
      , EXECUT_CYCLE
      , EXECUT_SCHDUL_DE
      , EXECUT_SCHDUL_HOUR
      , EXECUT_SCHDUL_MNT
      , EXECUT_SCHDUL_SECND
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{batchSchdulId}
        , #{batchOpertId}
        , #{executCycle}
        , #{executSchdulDe}
        , #{executSchdulHour}
        , #{executSchdulMnt}
        , #{executSchdulSecnd}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_BATCH_SCHDUL
   SET  EXECUT_CYCLE = #{executCycle}
      , EXECUT_SCHDUL_DE = #{executSchdulDe}
      , EXECUT_SCHDUL_HOUR = #{executSchdulHour}
      , EXECUT_SCHDUL_MNT = #{executSchdulMnt}
      , LAST_UPDUSR_ID = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  BATCH_SCHDUL_ID = #{batchSchdulId}
